def bands_for(need):
    """recency.py's overlapping frontier bands PLUS explicit per-calendar-year windows.

    We keep the headline overlapping bands {since 2023 boundary | last 12 months | online-ahead-of-print}
    and add {2023 | 2024 | 2025} year windows for balanced coverage. We DROP the two redundant bands
    `last_24_months` (a strict subset of since_boundary and of the year windows) and
    `newly_indexed_since_last_run` (an index-date filter, redundant with the recent windows, and the one
    OpenAlex throttled hardest) so the shared-IP rate budget goes to the value-bearing queries.
    """
    keep = {"since_boundary", "last_12_months", "ahead_of_print"}
    profile_bands = [b for b in R.resolve_bands(need, PROFILE) if b.key in keep]
    return profile_bands + year_bands()
